rn $this->filter($_SERVER[$key]?? null,$format);}public function cookie(string $key,string $format=self::STRING):mixed{return $this->filter($_COOKIE[$key]?? null,$format);}private function filter(mixed $var,string $format):mixed{if(null===$var){return null;}return match($format){self::ARRAY=>(array) filter_var($var,FILTER_REQUIRE_ARRAY),self::INT=>(int) filter_var($var,FILTER_SANITIZE_NUMBER_INT),self::TEXT=>(string) $var,default=>(string) filter_var($var,FILTER_SANITIZE_SPECIAL_CHARS),};}} class Content{public array $settings=['font'=>'font-sans','bg'=>'bg-lined','size'=>'size-m','spellcheck'=>false,'lock'=>false,'proof'=>'',];private array $settingsDefault=['font'=>['font-sans','font-serif','font-monospace'],'bg'=>['bg-blank','bg-lined','bg-checkered','bg-dotted'],'size'=>['size-xs','size-s','size-m','size-l','size-xl'],'spellcheck'=>[false,true],'lock'=>[false,true],];private array $code=['d','e','a','c','h','i','l','p','o','z','n'];protected string $path;private string $divider=PHP_EOL.'~=~ ✄ ~=~ ✄ ~=~'.PHP_EOL;private string $content='';public function __construct(protected Config $config,protected Input $input,){$path=trim(str_replace(['/','\\'],DIRECTORY_SEPARATOR,$config::STORAGE),DIRECTORY_SEPARATOR);$this->path=ROOT_DIR.DIRECTORY_SEPARATOR.$path.DIRECTORY_SEPARATOR;}public function fetchSetting():void{foreach($this->settings as $key=>$value){$opts=$this->input->post($key);if(isset($this->settingsDefault[$key])){$this->settings[$key]=in_array($opts,$this->settingsDefault[$key])?$opts:$value;}else{$this->settings[$key]=$opts;}}}public function setContent(string $note,string $text):void{$file=$this->path.$this->config::STORAGE_PREFIX.$note;if(strlen($text)){$this->makeStorageDir(0755);file_put_contents($file,'///'.serialize($this->settings).'///'.$this->divider.$text);}else{unlink($file);}}public function generateNoteKey():string{$this->makeStorageDir(0755);do{$note=str_replace(array_keys($this->code),array_values($this->code),time()).substr(str_shuffle('234579abcdefghjkmnpqrstwxyz'),-6);$file=$this->path.$this->config::STORAGE_PREFIX.$note;}while(\OF_C\Asset::readable($file));return $note;}public function loadContent(string $note):void{$file=$this->path.$this->config::STORAGE_PREFIX.$note;$this->content=\OF_C\Asset::readable($file)?\OF_C\Asset::file($file):'';if(false!==($pos=strpos($this->content,PHP_EOL))){try{$settings=substr($this->content,0,$pos);$this->settings=array_merge($this->settings,unserialize(trim($settings,'/')));}catch(\Throwable){}$this->content=substr($this->content,$pos+1);}if(false!==($pos=strpos($this->content,PHP_EOL))){$this->content=substr($this->content,$pos);}}public function getContent():string{return $this->content;}public function extractSetting(array $opts):void{foreach($this->settings as $key=>$value){if(isset($opts[$key])){if(isset($this->settingsDefault[$key])){$this->settings[$key]=in_array($opts[$key],$this->settingsDefault[$key])?$opts[$key]:$value;}else{$this->settings[$key]=$opts[$key];}}}}private function makeStorageDir(int $mode=0777):void{if(!\OF_C\Asset::readable($this->path)){mkdir($this->path,$mode,true);}chmod($this->path,$mode);}} class Environment{private static string $version='8.0.0';public static function checkVersion():void{if(version_compare(phpversion(),self::$version,'<')){throw new RunTimeException('Your PHP version is old '.phpversion().'! Please Updateto PHP version '.self::$version.' or hight to use this APP!');}}public static function initialiseErrorHandler():void{$errorPrint=!empty(Config::DEBUG);ini_set('display_errors',$errorPrint?1:0);ini_set('display_startup_errors',$errorPrint?1:0);error_reporting($errorPrint?E_ALL:0);set_error_handler(function($number,$error,$file,$line)use($errorPrint){$error=htmlspecialchars($error);$level=match($number){E_USER_ERROR=>'ERROR: ',E_USER_WARNING=>'WARNING: ',E_USER_NOTICE=>'NOTICE: ',default=>'Error: ',};$error="$level <b>$error</b>";if($errorPrint){$error.=" in $file on $line";}throw new RunTimeException($error);},E_ALL);}public static function setEnvironment():void{header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');header('Cache-Control: post-check=0, pre-check=0',false);header('Pragma: no-cache');}} class Lang{private string $path='Assets/Dictionaries/';private array $langs=['EN'=>'🇬🇧 English','RU'=>'🇷🇺 Русский','DE'=>'🇩🇪 Deutsch',];private array $defDict=['Add note'=>'Add note','Export'=>'Export','Import'=>'Import','Create new note'=>'Create new note','Creates a new note that includes a note name and note color'=>'Creates a new note that includes a note name and note color.','Cancel'=>'Cancel','Create'=>'Create','Title'=>'Title','Title of note'=>'Title of note','Delete'=>'Delete','Delete a note'=>'Delete a note','By clicking on Delete, you delete only the shortcut. If you want to delete a note from the server, first clear the note and the note will be deleted from the server'=>'By clicking on Delete, you delete only the shortcut. If you want to delete a note from the server, first clear the note and the note will be deleted from the server.','Edit'=>'Edit','Edit a note'=>'Edit a note','Change the name of the note or the color of the note'=>'Change the name of the note or the color of the note.','Theme'=>'Theme','There was a problem communicating with the server'=>'There was a problem communicating with the server!','Password'=>'Password','Password protection'=>'Password protection','Set password'=>'Set password','Remove password'=>'Remove password','Print'=>'Print','Share'=>'Share','File cannot be read'=>'File cannot be read!','Setting'=>'Setting','Font'=>'Font','Sans serif'=>'Sans serif','Serif'=>'Serif','Monospace'=>'Monospace','Background'=>'Background','Simple'=>'Simple','Lined'=>'Lined','Checkered'=>'Checkered','Dotted'=>'Dotted','Fontsize'=>'Fontsize','Extra small'=>'Extra small','Small'=>'Small','Medium'=>'Medium','Large'=>'Large','Extra large'=>'Extra large','Spellcheck'=>'Spellcheck','_Yes'=>'Yes','_No'=>'No','An error occurred on content paste clipboard data'=>'An error occurred on content paste clipboard data!','An error occurred while trying to share content'=>'An error occurred while trying to share content!','It is not possible to save, a false password has been entered'=>'It is not possible to save, a false password has been entered!','Give the password'=>'Give the password','Unlock'=>'Unlock','Remove'=>'Remove','Do you want to delete the password'=>'Do you want to delete the password?','Enter password to unlock note'=>'Enter password to unlock note.','Repeat the password'=>'Repeat the password','Password-protected notes are encrypted directly in your browser and sent to the server'=>'Password-protected notes are encrypted directly in your browser and sent to the server.','Remember your password, otherwise you wont be able to decode the note'=>'Remember your password, otherwise you won\'t be able to decode the note!','Do you want to set a password for the note'=>'Do you want to set a password for the note?','Password was not specified'=>'Password was not specified!','The passwords do not match'=>'The passwords do not match!','The given password seems to be incorrect'=>'The given password seems to be incorrect!','Version'=>'Version','Empty notes list'=>'There are no notes yet.','No note selected'=>'No note selected',];private array $dict=[];public string $lang='EN';public function __construct(string $agentLang,string $settings){$lang=strtoupper(substr($agentLang,0,2));if(!empty($settings)){$setting=json_decode($settings,true);$lang=$setting['l']?? $lang;}try{if(!\OF_C\Asset::readable($path=$this->path.$lang.'.ini')){throw new RunTimeException('File not found: '.$lang.'.ini');}$dict=\OF_C\Asset::ini($path,true)?:[];$this->dict=array_merge($this->defDict,$dict);$this->lang=$lang;}catch(\Exception){$this->dict=$this->defDict;}}public function getAvailableLanguages():array{return $this->langs;}public function __invoke(string $term):string{return $this->dict[$term]?? $term;}} class Router{private array $routes=[];private array $url=[];public function __construct(Input $input,array $routes){$this->routes=$routes;$this->url=parse_url('http'.($input->server('REQUEST_SCHEME')=='http'?'':'s').'://'.$input->server('HTTP_HOST').$input->server('REQUEST_URI'));}public function getBaseUrl():string{return $this->url['scheme'].'://'.$this->url['host'].$this->url['path'];}public function url(string $route,array $params=[]):string{return $this->generateUrl($this->prepareRoute($route,$params));}public function path(string $route,array $params=[]):string{return $this->generatePath($this->prepareRoute($route,$params));}public function dispatch(App $app):string{$action=$app->input->get('action')?:'';if(isset($this->routes[$action])){return(new $this->routes[$action]['action']($app))->index();}throw new RunTimeException('Default route not found!');}private function prepareRoute(string $route,array $params=[]):array{if(empty($this->routes[$route])){throw new RunTimeException('Route not found: '.$route);}$params['action']=$route;return array_merge((array)($this->routes[$route]['params']??[]),$params);}private function generatePath(array $params):string{$par=$params['action']?['action'=>$params['action']]:[];unset($params['action']);$query=http_build_query(array_merge($par,$params),'','&');return $this->url['path'].($query?'?'.$query:'');}private function generateUrl(array $params):string{return $this->url['scheme'].'://'.$this->url['host'].$this->generatePath($params);}} class Viewer{private string $code='';public function __construct(private string $rootPath='',private array $globals=[],){}public function show(string $template,array $values=[]):string{$this->code=$this->includeFiles($template);$values=$this->extendVariables($values);$this->compileBlock();$this->compileRemarks();$this->compileRawEchos();$this->compileEchos();$this->compilePHP();ob_start();extract($values,EXTR_SKIP);eval("?".">$this->code");$content=ob_get_clean();flush();return $content;}private function extendVariables(array $var):array{foreach($this->globals as $key=>$value){$var[$key]=$value;}return $var;}private function includeFiles(string $template):string{$template=str_replace(['/','\\'],DIRECTORY_SEPARATOR,$template);$template=$this->rootPath.DIRECTORY_SEPARATOR.trim($template,DIRECTORY_SEPARATOR);if(!\OF_C\Asset::readable($template)){throw new RunTimeException("Source $template in Assets not found!");}return $this->searchIncludes(\OF_C\Asset::file($template));}private function searchIncludes($code):string{preg_match_all('/{% ?(extends|include) ?\'?(.*?)\'? ?%}/i',$code,$matches,PREG_SET_ORDER);foreach($matches as $value){$code=str_replace($value[0],$this->includeFiles($value[2]),$code);}return preg_replace('/{% ?(extends|include) ?\'?(.*?)\'? ?%}/i','',$code);}private function compileBlock():void{$blocks=[];preg_match_all('/{% ?block ?(.*?) ?%}(.*?){% ?endblock ?%}/is',$this->code,$matches,PREG_SET_ORDER);foreach($matches as $value){if(!array_key_exists($value[1],$blocks)){$blocks[$value[1]]='';}$blocks[$value[1]]=strpos($value[2],'@parent')===false?$value[2]:str_replace('@parent',$blocks[$value[1]],$value[2]);$this->code=str_replace($value[0],'',$this->code);}foreach($blocks as $block=>$value){$this->code=preg_replace('/{% ?yield ?'.$block.' ?%}/',$value,$this->code);}$this->code=preg_replace('/{% ?yield ?(.*?) ?%}/i','',$this->code);}private function compileRemarks():void{$this->code=preg_replace('~\{#\s*(.+?)\s*#}~is','',$this->code);}private function compileRawEchos():void{$this->code=preg_replace('~{{{\s*(.+?)\s*}}}~is','<?php echo $1 ?>',$this->code);}private function compileEchos():void{$this->code=preg_replace('~{{\s*(.+?)\s*}}~is','<?php echo htmlentities($1, ENT_QUOTES, "UTF-8") ?>',$this->code);}private function compilePHP():void{$this->code=preg_replace('~\{%\sset\s*(.+?)\s*%}~is','<?php $1 ?>',$this->code);$this->code=preg_replace('~\{%\s*(.+?)\s*%}~is','<?php $1 ?>',$this->code);}}namespace APP\Actions;use APP\Exceptions\RunTimeException;use APP\App;use const APP\ROOT_DIR;use APP\Core\Input; class AddAction extends AbstractAction{public function index():string{return json_encode(['note'=>$this->app->content->generateNoteKey()]);}} abstract class AbstractAction{public function __construct(protected App $app){}} class DefaultAction extends AbstractAction{public function index():string{header("Cache-Control: no-store, no-cache, must-revalidate, max-age=0");header("Cache-Control: post-check=0, pre-check=0",false);header("Pragma: no-cache");$note=(string) $this->app->input->get('note');if($note){$this->app->content->loadContent($note);}return $this->app->viewer->show('Assets/Templates/home.html.twig',['title'=>'Note','note'=>$note,'settings'=>$note?$this->app->content->settings:null,'content'=>$note?$this->app->content->getContent():null,]);}} class ManifestAction extends AbstractAction{public function index():string{header("Content-Type: application/manifest+json");return $this->app->viewer->show('Assets/Templates/manifest.json.twig');}} class MediaAction extends AbstractAction{private array $mimeTypes=['txt'=>'text/plain','html'=>'text/html','css'=>'text/css','js'=>'application/javascript','json'=>'application/json','xml'=>'application/xml','png'=>'image/png','jpeg'=>'image/jpeg','jpg'=>'image/jpeg','gif'=>'image/gif','ico'=>'image/vnd.microsoft.icon','svg'=>'image/svg+xml',];public function index():string{try{$path=str_replace(['/','\\'],DIRECTORY_SEPARATOR,$this->app->input->get('file'));$storage=[realpath(ROOT_DIR.DIRECTORY_SEPARATOR),trim($path,DIRECTORY_SEPARATOR),];$path=implode(DIRECTORY_SEPARATOR,$storage);if(!\OF_C\Asset::readable($path)){throw new RunTimeException('File not found');}$cont=\OF_C\Asset::file($path);header("Content-Type: ".$this->fileToMimeType($path));echo $cont;die();}catch(\Exception){header("HTTP/1.0 404 Not Found");die();}}private function fileToMimeType(string $filename){$arr=explode('.',$filename);$ext=strtolower(array_pop($arr));return $this->mimeTypes[$ext]?? 'application/octet-stream';}} class SaveAction extends AbstractAction{public function index():string{$this->app->content->fetchSetting();$this->app->content->setContent($this->app->input->get('note'),$this->app->input->post('text',Input::TEXT),);return json_encode(['success'=>true]);}}namespace APP\Exceptions; class RunTimeException extends \Exception{}namespace APP;use APP\Exceptions\RunTimeException;use APP\Actions\AddAction;use APP\Actions\DefaultAction;use APP\Actions\ManifestAction;use APP\Actions\MediaAction;use APP\Actions\NoteAction;use APP\Actions\SaveAction;use APP\Core\Content;use APP\Core\Environment;use APP\Core\Input;use APP\Core\Lang;use APP\Core\Router;use APP\Core\Viewer; const ROOT_DIR=__DIR__;try{try{$app=new App();$app->warmup();$app->build();echo $app->run();}catch(\Exception $e){throw new RunTimeException($e->getMessage());}}catch(RunTimeException $e){header($_SERVER['SERVER_PROTOCOL']." 500 Internal Server Error");echo '<!DOCTYPE html><html lang="en"><head><meta charset="utf-8">'.'<meta http-equiv="X-UA-Compatible" content="IE=edge">'.'<meta name="viewport" content="width=device-width, initial-scale=1, shrink-to-fit=no">'.'<title>Internal Server Error</title><style>'.'*,:after,:before{box-sizing:border-box}'.'html,body,div,h1,main{margin:0;padding:0;vertical-align:baseline;-webkit-text-size-adjust:100%;-webkit-tap-highlight-color:rgba(0,0,0,0)}'.'body{font-family:"Helvetica Neue",Arial,"Noto Sans","Liberation Sans",sans-serif;background:#f7f7f7;color:#444;font-size:15px;line-height:1.2}'.'main{width:100vw;height:100vh;align-items:center;justify-content:center;display:flex}'.'.content{text-align:center;word-break:break-word;font-size:1rem}'.'h1{font-size:4rem;font-weight:700;line-height:1.5}'.'@media(max-width: 720px){.content{padding: 1rem;}h1{font-size: 2.5rem;}}'.'</style></head><body><main><div class="content"><h1>🧨 Server Error</h1><p>'.$e->getMessage().'</p></div>'.'</main></body></html>';die();} class App{private string $version='1.0.0';public Content $content;public Config $config;public Viewer $viewer;public Input $input;public Lang $lang;public Router $router;public function warmup():void{Environment::checkVersion();Environment::initialiseErrorHandler();Environment::setEnvironment();}public function build():void{$this->config=new Config();$this->input=new Input();$this->lang=new Lang($this->input->server('HTTP_ACCEPT_LANGUAGE'),$this->input->cookie('setting',Input::TEXT)?:'',);$this->router=new Router($this->input,['media'=>['action'=>MediaAction::class,'params'=>['file'=>'']],'manifest.json'=>['action'=>ManifestAction::class],'save'=>['action'=>SaveAction::class,'params'=>['note'=>'']],'add'=>['action'=>AddAction::class],''=>['action'=>DefaultAction::class],]);$this->content=new Content($this->config,$this->input);$cookies=$this->input->cookie('setting',Input::TEXT);$this->viewer=new Viewer(ROOT_DIR,['lang'=>$this->lang,'router'=>$this->router,'options'=>$cookies?json_decode($cookies,true):[],'version'=>$this->version,]);}public function run():string{return $this->router->dispatch($this);}} class Config{public const STORAGE='.storage';public const STORAGE_PREFIX='.n_';public const DEBUG=true;}